from flask import Flask, request, jsonify
from bson import ObjectId
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB at localhost:27017
client = MongoClient('mongodb://localhost:27017/')
db = client['mydatabase']

@app.route('/users', methods=['GET'])
def get_users():
    users = db.users.find()
    return jsonify([user for user in users])

@app.route('/users/<string:username>', methods=['GET'])
def get_user(username):
    user = db.users.find_one({'username': username})
    if user is None:
        return jsonify({'error': 'User not found'}), 404
    else:
        return jsonify(user)

@app.route('/users', methods=['POST'])
def create_user():
    data = request.get_json()
    user = db.users.insert_one({'username': data['username'], 'password': data['password']})
    return jsonify(user), 201

@app.route('/users/<string:username>', methods=['PUT'])
def update_user(username):
    data = request.get_json()
    user = db.users.find_one({'username': username})
    if user is None:
        return jsonify({'error': 'User not found'}), 404
    else:
        db.users.update_one({'_id': ObjectId(user['_id'])}, {'$set': {'password': data['password']}})
        return jsonify(user), 200

@app.route('/users/<string:username>', methods=['DELETE'])
def delete_user(username):
    user = db.users.find_one({'username': username})
    if user is None:
        return jsonify({'error': 'User not found'}), 404
    else:
        db.users.delete_one({'_id': ObjectId(user['_id'])})
        return jsonify({'message': 'User deleted successfully'}), 200

