@app.route('/documents', methods=['POST'])
def create_document():
    data = request.get_json()
    document = db.documents.insert_one({'title': data['title'], 'content': data['content']})
    return jsonify(document), 201

@app.route('/documents/<string:title>', methods=['PUT'])
def update_document(title):
    data = request.get_json()
    document = db.documents.find_one({'title': title})
    if document is None:
        return jsonify({'error': 'Document not found'}), 404
    else:
        db.documents.update_one({'_id': ObjectId(document['_id'])}, {'$set': {'content': data['content']}})
        return jsonify(document), 200

@app.route('/documents/<string:title>', methods=['DELETE'])
def delete_document(title):
    document = db.documents.find_one({'title': title})
    if document is None:
        return jsonify({'error': 'Document not found'}), 404
    else:
        db.documents.delete_one({'_id': ObjectId(document['_id'])})
        return jsonify({'message': 'Document deleted successfully'}), 200

@app.route('/aggregate', methods=['POST'])
def aggregate():
    data = request.get_json()
    pipeline = [{'$match': {'title': data['title']}}, {'$group': {'_id': '$author', 'count': {'$sum': 1}}}]
    result = db.documents.aggregate(pipeline)
    return jsonify(result), 200